package net.unit8.souther.runtime;

/** Option helpers the generated bytecode calls (spec §stdlib-option). {@code Option} is not
 *  surface-writable (spec §algebraic-types): a Souther body cannot rebuild a {@code Some}, so the transforming
 *  operation lives here in the kernel. {@code withDefault}, which only reads an option, needs no
 *  kernel — it is an ordinary self-hosted helper in {@code souther.option}. */
public final class Options {

    private Options() {}

    /** Maps the contained value through {@code f}, keeping {@code None} as {@code None}; {@code f}
     *  never sees a {@code None}. The step is a first-class function value, applied to the wrapped
     *  value and its result rewrapped in a fresh {@code Some}. */
    public static Option<Object> map(Fn f, Option<?> o) {
        return o instanceof Option.Some<?> s
                ? Option.some(f.apply(new Object[] {s.value()}))
                : Option.none();
    }
}
